    val catalogue: PhysicsFormulaCatalogue by lazy {
        val subcategories = seeds.flatMap { seed -> seed.topics.map { title -> PhysicsFormulaSubcategory("${seed.id}-${slug(title)}", seed.id, title, "Formula relationships and validity conditions for $title.") } }
        val categories = seeds.map { seed -> PhysicsFormulaCategory(seed.id, seed.title, "A structured formula collection for ${seed.title.lowercase()}.", subcategories.filter { it.categoryId == seed.id }.map { it.id }) }
        PhysicsFormulaCatalogue(SCHEMA_VERSION, categories, subcategories, formulas(subcategories))
    }

    private fun formulas(subcategories: List<PhysicsFormulaSubcategory>): List<PhysicsFormula> {
        fun f(id: String, category: String, subcategory: String, title: String, equation: String, spoken: String, level: PhysicsFormulaLevel, vars: String, example: String, calculator: Boolean = true, derivation: Boolean = true, keywords: String = title): PhysicsFormula {
            val subId = subcategories.first { it.categoryId == category && it.title == subcategory }.id
            val variables = vars.split(';').filter(String::isNotBlank).map { spec -> spec.split('|').let { PhysicsFormulaVariable(it[0], it[1], it[2], it[2], it.getOrNull(3)?.ifBlank { null }, it.getOrNull(4)?.ifBlank { null }) } }
            return PhysicsFormula(id, category, subId, title, equation, equation.replace("²", "^2").replace("·", "*"), spoken, "Use this relationship within its stated physical assumptions and with consistent units.", level, variables,
                listOf("Quantities use a consistent reference frame and SI units unless stated otherwise."), listOf("The relationship applies only under the model conditions shown."),
                emptyList(), if (derivation) listOf(PhysicsDerivationStep(equation, "This form follows from the defining relationship and algebraic isolation of the required quantity.")) else emptyList(),
                listOf(PhysicsWorkedExample(example, "Substitute the known values in SI units.", "Evaluate and report the requested quantity with its unit.", "Both sides reduce to compatible SI dimensions.")),
                "The left and right sides have matching SI dimensions.", if (calculator) PhysicsCalculatorDefinition(variables.map { it.id }.toSet(), variables.map { it.id }.toSet()) else null,
                emptyList(), emptyList(), (keywords.lowercase().split(Regex("[^a-z0-9]+")) + title.lowercase().split(' ')).filter { it.isNotBlank() }.toSet(), featured = level.rank <= PhysicsFormulaLevel.Class10.rank)
        }
        return listOf(
            f("physics-percentage-error", "measurements-units", "Percentage Error", "Percentage error", "percentage error = |measured − accepted| / |accepted| × 100%", "percentage error equals absolute difference divided by accepted value times one hundred percent", PhysicsFormulaLevel.Class9, "measured|xₘ|measured value||;accepted|xₐ|accepted value||", "Compare a 9.8 m measurement with an accepted 10.0 m value."),
            f("physics-speed", "motion-kinematics", "Speed and Velocity", "Average speed", "v = d / t", "speed equals distance divided by time", PhysicsFormulaLevel.Class7, "speed|v|speed|m/s|[L T⁻¹];distance|d|distance|m|[L];time|t|time|s|[T]", "A runner covers 100 m in 20 s.", keywords = "speed velocity distance time"),
            f("physics-final-velocity", "motion-kinematics", "Uniformly Accelerated Motion", "Final velocity", "v = u + at", "final velocity equals initial velocity plus acceleration multiplied by time", PhysicsFormulaLevel.Class9, "finalVelocity|v|final velocity|m/s|[L T⁻¹];initialVelocity|u|initial velocity|m/s|[L T⁻¹];acceleration|a|acceleration|m/s²|[L T⁻²];time|t|time|s|[T]", "A body starts at 2 m/s and accelerates at 3 m/s² for 4 s.", keywords = "kinematic acceleration final velocity"),
            f("physics-newton-second-law", "newtonian-mechanics", "Newton's Laws", "Newton's second law", "F = ma", "net force equals mass multiplied by acceleration", PhysicsFormulaLevel.Class8, "force|F|net force|N|[M L T⁻²];mass|m|mass|kg|[M];acceleration|a|acceleration|m/s²|[L T⁻²]", "Find the force accelerating 5 kg at 2 m/s².", keywords = "force newton second law acceleration"),
            f("physics-kinetic-energy", "work-energy-power", "Kinetic Energy", "Kinetic energy", "Eₖ = ½mv²", "kinetic energy equals one half mass multiplied by speed squared", PhysicsFormulaLevel.Class9, "energy|Eₖ|kinetic energy|J|[M L² T⁻²];mass|m|mass|kg|[M];speed|v|speed|m/s|[L T⁻¹]", "Find the kinetic energy of 2 kg moving at 3 m/s.", keywords = "energy work kinetic"),
            f("physics-momentum", "momentum-collisions", "Linear Momentum", "Linear momentum", "p = mv", "momentum equals mass multiplied by velocity", PhysicsFormulaLevel.Class9, "momentum|p|momentum|kg·m/s|[M L T⁻¹];mass|m|mass|kg|[M];velocity|v|velocity|m/s|[L T⁻¹]", "Find the momentum of 4 kg moving at 5 m/s."),
            f("physics-torque", "rotational-mechanics", "Torque", "Torque magnitude", "τ = rF sin θ", "torque equals radius times force times sine of the angle", PhysicsFormulaLevel.Class11, "torque|τ|torque|N·m|[M L² T⁻²];radius|r|lever arm|m|[L];force|F|force|N|[M L T⁻²];angle|θ|angle|rad|1", "A 10 N force acts 0.5 m from a pivot at right angles."),
            f("physics-gravitation", "gravitation", "Universal Gravitation", "Newton's law of gravitation", "F = Gm₁m₂ / r²", "force equals the gravitational constant times both masses divided by separation squared", PhysicsFormulaLevel.Class11, "force|F|gravitational force|N|[M L T⁻²];mass1|m₁|first mass|kg|[M];mass2|m₂|second mass|kg|[M];radius|r|centre separation|m|[L]", "Find the attraction between two known masses separated by a known distance."),
            f("physics-density", "properties-matter", "Density", "Density", "ρ = m / V", "density equals mass divided by volume", PhysicsFormulaLevel.Class8, "density|ρ|density|kg/m³|[M L⁻³];mass|m|mass|kg|[M];volume|V|volume|m³|[L³]", "A 2 kg sample occupies 0.001 m³."),
            f("physics-pressure", "fluids", "Pressure", "Pressure", "p = F / A", "pressure equals normal force divided by area", PhysicsFormulaLevel.Class8, "pressure|p|pressure|Pa|[M L⁻¹ T⁻²];force|F|normal force|N|[M L T⁻²];area|A|area|m²|[L²]", "A 200 N force acts over 0.5 m²."),
            f("physics-pendulum", "oscillations", "Pendulum", "Simple pendulum period", "T = 2π√(L/g)", "period equals two pi times the square root of length divided by gravitational acceleration", PhysicsFormulaLevel.Class11, "period|T|period|s|[T];length|L|pendulum length|m|[L];gravity|g|gravitational acceleration|m/s²|[L T⁻²]", "Estimate the period of a 1 m pendulum for small oscillations."),
            f("physics-wave-speed", "waves", "Wave Equation", "Wave speed", "v = fλ", "wave speed equals frequency multiplied by wavelength", PhysicsFormulaLevel.Class9, "speed|v|wave speed|m/s|[L T⁻¹];frequency|f|frequency|Hz|[T⁻¹];wavelength|λ|wavelength|m|[L]", "A 5 Hz wave has wavelength 2 m.", keywords = "wave speed frequency wavelength"),
            f("physics-decibel", "sound", "Decibel Scale", "Sound intensity level", "β = 10 log₁₀(I/I₀)", "sound level equals ten times the base ten logarithm of intensity ratio", PhysicsFormulaLevel.Class11, "level|β|sound level|dB|1;intensity|I|sound intensity|W/m²|[M T⁻³];reference|I₀|reference intensity|W/m²|[M T⁻³]", "Compare an intensity with the standard reference intensity."),
            f("physics-heat", "thermodynamics", "Specific Heat", "Sensible heat", "Q = mcΔT", "heat equals mass times specific heat capacity times temperature change", PhysicsFormulaLevel.Class9, "heat|Q|heat transferred|J|[M L² T⁻²];mass|m|mass|kg|[M];capacity|c|specific heat capacity|J/(kg·K)|[L² T⁻² K⁻¹];temperature|ΔT|temperature change|K|[K]", "Heat 1 kg of water through 10 K."),
            f("physics-coulomb", "electrostatics", "Coulomb's Law", "Coulomb's law", "F = k|q₁q₂| / r²", "force magnitude equals Coulomb constant times charge product divided by separation squared", PhysicsFormulaLevel.Class11, "force|F|electric force|N|[M L T⁻²];charge1|q₁|first charge|C|[I T];charge2|q₂|second charge|C|[I T];radius|r|separation|m|[L]", "Find the force between two point charges."),
            f("physics-ohm", "current-electricity", "Ohm's Law", "Ohm's law", "V = IR", "voltage equals current multiplied by resistance", PhysicsFormulaLevel.Class10, "voltage|V|potential difference|V|[M L² T⁻³ I⁻¹];current|I|current|A|[I];resistance|R|resistance|Ω|[M L² T⁻³ I⁻²]", "A 2 A current passes through 5 Ω.", keywords = "ohm voltage current resistance electricity"),
            f("physics-magnetic-force", "magnetism", "Force on Charge", "Magnetic force magnitude", "F = qvB sin θ", "force equals charge times speed times magnetic field times sine of angle", PhysicsFormulaLevel.Class12, "force|F|magnetic force|N|[M L T⁻²];charge|q|charge|C|[I T];speed|v|speed|m/s|[L T⁻¹];field|B|magnetic field|T|[M T⁻² I⁻¹];angle|θ|angle|rad|1", "A charge moves through a uniform magnetic field."),
            f("physics-faraday", "electromagnetic-induction", "Faraday's Law", "Faraday's law", "ε = −N ΔΦ/Δt", "induced emf equals negative turns times rate of change of magnetic flux", PhysicsFormulaLevel.Class12, "emf|ε|induced emf|V|[M L² T⁻³ I⁻¹];turns|N|number of turns||1;flux|ΔΦ|flux change|Wb|[M L² T⁻² I⁻¹];time|Δt|time interval|s|[T]", "A coil experiences a known flux change in a known time."),
            f("physics-ac-rms", "alternating-current", "RMS Values", "Sinusoidal RMS voltage", "Vᵣₘₛ = V₀/√2", "root mean square voltage equals peak voltage divided by square root of two", PhysicsFormulaLevel.Class12, "rms|Vᵣₘₛ|RMS voltage|V|[M L² T⁻³ I⁻¹];peak|V₀|peak voltage|V|[M L² T⁻³ I⁻¹]", "Convert 325 V peak sinusoidal voltage to RMS."),
            f("physics-photon", "electromagnetic-waves", "Energy", "Photon energy", "E = hf", "photon energy equals Planck constant multiplied by frequency", PhysicsFormulaLevel.Class12, "energy|E|photon energy|J|[M L² T⁻²];frequency|f|frequency|Hz|[T⁻¹]", "Find photon energy for a known frequency."),
            f("physics-thin-lens", "ray-optics", "Lenses", "Thin-lens equation", "1/f = 1/v − 1/u", "inverse focal length equals inverse image distance minus inverse object distance under Cartesian sign convention", PhysicsFormulaLevel.Class10, "focal|f|focal length|m|[L];image|v|image distance|m|[L];object|u|object distance|m|[L]", "Find image distance from object distance and focal length.", keywords = "lens equation optics focal image"),
            f("physics-fringe-width", "wave-optics", "Young's Double Slit", "Fringe width", "β = λD/d", "fringe width equals wavelength times screen distance divided by slit separation", PhysicsFormulaLevel.Class12, "width|β|fringe width|m|[L];wavelength|λ|wavelength|m|[L];distance|D|screen distance|m|[L];separation|d|slit separation|m|[L]", "Calculate fringe spacing for a double-slit setup."),
            f("physics-photoelectric", "modern-physics", "Photoelectric Effect", "Einstein photoelectric equation", "Kₘₐₓ = hf − φ", "maximum kinetic energy equals photon energy minus work function", PhysicsFormulaLevel.Class12, "energy|Kₘₐₓ|maximum kinetic energy|J|[M L² T⁻²];frequency|f|frequency|Hz|[T⁻¹];work|φ|work function|J|[M L² T⁻²]", "Find emitted-electron maximum energy above threshold."),
            f("physics-radioactive-decay", "nuclear-physics", "Radioactive Decay", "Radioactive decay law", "N = N₀e^(−λt)", "remaining nuclei equal initial nuclei times exponential negative decay constant times time", PhysicsFormulaLevel.Class12, "remaining|N|remaining nuclei||1;initial|N₀|initial nuclei||1;constant|λ|decay constant|s⁻¹|[T⁻¹];time|t|elapsed time|s|[T]", "Find the remaining fraction after a known time."),
            f("physics-transistor-current", "electronics", "Transistors", "Transistor current relation", "Iₑ = Iᵦ + I꜀", "emitter current equals base current plus collector current", PhysicsFormulaLevel.Class12, "emitter|Iₑ|emitter current|A|[I];base|Iᵦ|base current|A|[I];collector|I꜀|collector current|A|[I]", "Find emitter current from base and collector currents."),
            f("physics-lagrangian", "advanced-physics", "Lagrangian Mechanics", "Euler–Lagrange equation", "d/dt(∂L/∂q̇) − ∂L/∂q = 0", "time derivative of partial L by partial q dot minus partial L by partial q equals zero", PhysicsFormulaLevel.Undergraduate, "lagrangian|L|Lagrangian|J|[M L² T⁻²];coordinate|q|generalised coordinate||;time|t|time|s|[T]", "Apply the equation to a one-dimensional conservative system.", calculator = false, keywords = "lagrangian advanced mechanics calculus"),
